import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface ReportRequest {
    report_type: 'performance' | 'campaigns' | 'creatives' | 'audits';
    date_from?: string;
    date_to?: string;
    campaign_id?: string;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        const { data: userData } = await supabase
            .from('users')
            .select('company_id, companies(name)')
            .eq('id', user.id)
            .single();

        if (!userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const { report_type, date_from, date_to, campaign_id } = await req.json() as ReportRequest;

        const companyId = userData.company_id;
        const companyName = (userData as any).companies?.name || 'Empresa';
        const dateFromStr = date_from || new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
        const dateToStr = date_to || new Date().toISOString().split('T')[0];

        let reportData: Record<string, unknown> = {
            company_name: companyName,
            report_type,
            date_from: dateFromStr,
            date_to: dateToStr,
            generated_at: new Date().toISOString(),
        };

        // Fetch data based on report type
        if (report_type === 'performance' || report_type === 'campaigns') {
            const { data: campaigns } = await supabase
                .from('campaigns')
                .select('id, name, status, objective, impressions, clicks, spend, conversions')
                .eq('company_id', companyId);

            const totals = (campaigns || []).reduce(
                (acc, c) => ({
                    impressions: acc.impressions + (c.impressions || 0),
                    clicks: acc.clicks + (c.clicks || 0),
                    spend: acc.spend + (Number(c.spend) || 0),
                    conversions: acc.conversions + (c.conversions || 0),
                }),
                { impressions: 0, clicks: 0, spend: 0, conversions: 0 }
            );

            reportData = {
                ...reportData,
                summary: {
                    total_campaigns: campaigns?.length || 0,
                    active_campaigns: campaigns?.filter(c => c.status === 'active').length || 0,
                    total_impressions: totals.impressions,
                    total_clicks: totals.clicks,
                    total_spend: totals.spend.toFixed(2),
                    total_conversions: totals.conversions,
                    avg_ctr: totals.impressions > 0 ? ((totals.clicks / totals.impressions) * 100).toFixed(2) : '0',
                    avg_cpc: totals.clicks > 0 ? (totals.spend / totals.clicks).toFixed(2) : '0',
                },
                campaigns: campaigns?.slice(0, 20).map(c => ({
                    name: c.name,
                    status: c.status,
                    objective: c.objective,
                    impressions: c.impressions,
                    clicks: c.clicks,
                    spend: Number(c.spend || 0).toFixed(2),
                    ctr: c.impressions > 0 ? ((c.clicks / c.impressions) * 100).toFixed(2) : '0',
                })),
            };
        }

        if (report_type === 'creatives') {
            const query = supabase
                .from('creatives')
                .select('id, name, type, status, impressions, clicks, ctr, cpc, performance_score')
                .eq('company_id', companyId)
                .order('performance_score', { ascending: false })
                .limit(50);

            if (campaign_id) {
                query.eq('campaign_id', campaign_id);
            }

            const { data: creatives } = await query;

            reportData = {
                ...reportData,
                summary: {
                    total_creatives: creatives?.length || 0,
                    avg_ctr: creatives?.length
                        ? (creatives.reduce((a, c) => a + (c.ctr || 0), 0) / creatives.length).toFixed(2)
                        : '0',
                    avg_performance: creatives?.length
                        ? (creatives.reduce((a, c) => a + (c.performance_score || 0), 0) / creatives.length).toFixed(0)
                        : '0',
                },
                creatives: creatives?.map(c => ({
                    name: c.name,
                    type: c.type,
                    status: c.status,
                    impressions: c.impressions,
                    clicks: c.clicks,
                    ctr: c.ctr?.toFixed(2) || '0',
                    cpc: c.cpc?.toFixed(2) || '0',
                    score: c.performance_score || 0,
                })),
            };
        }

        if (report_type === 'audits') {
            const { data: audits } = await supabase
                .from('audits')
                .select('id, status, compliance_score, performance_score, created_at, creatives(name)')
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(50);

            const statusCounts = (audits || []).reduce(
                (acc, a) => {
                    if (a.status === 'approved') acc.approved++;
                    else if (a.status === 'rejected') acc.rejected++;
                    else acc.review++;
                    return acc;
                },
                { approved: 0, rejected: 0, review: 0 }
            );

            reportData = {
                ...reportData,
                summary: {
                    total_audits: audits?.length || 0,
                    ...statusCounts,
                    avg_compliance: audits?.length
                        ? (audits.reduce((a, au) => a + (au.compliance_score || 0), 0) / audits.length).toFixed(0)
                        : '0',
                },
                audits: audits?.map(a => ({
                    creative_name: (a as any).creatives?.name || 'N/A',
                    status: a.status,
                    compliance_score: a.compliance_score,
                    performance_score: a.performance_score,
                    date: a.created_at,
                })),
            };
        }

        // Generate HTML report
        const html = generateReportHtml(reportData, report_type);

        // Save report record
        await supabase.from('reports').insert({
            company_id: companyId,
            user_id: user.id,
            report_type,
            date_from: dateFromStr,
            date_to: dateToStr,
            data: reportData,
        });

        return new Response(html, {
            headers: {
                ...corsHeaders,
                'Content-Type': 'text/html; charset=utf-8',
            },
            status: 200,
        });

    } catch (error) {
        console.error('Report generation error:', error);
        return new Response(
            JSON.stringify({ success: false, error: String(error) }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});

function generateReportHtml(data: Record<string, unknown>, type: string): string {
    const summary = data.summary as Record<string, unknown>;
    const title = {
        performance: 'Relatório de Performance',
        campaigns: 'Relatório de Campanhas',
        creatives: 'Relatório de Criativos',
        audits: 'Relatório de Auditorias',
    }[type] || 'Relatório';

    let tableHtml = '';

    if (type === 'performance' || type === 'campaigns') {
        const campaigns = data.campaigns as Array<Record<string, unknown>> || [];
        tableHtml = `
      <table>
        <thead>
          <tr>
            <th>Campanha</th>
            <th>Status</th>
            <th>Impressões</th>
            <th>Cliques</th>
            <th>CTR</th>
            <th>Gasto</th>
          </tr>
        </thead>
        <tbody>
          ${campaigns.map(c => `
            <tr>
              <td>${c.name}</td>
              <td><span class="status-${c.status}">${c.status}</span></td>
              <td>${Number(c.impressions).toLocaleString('pt-BR')}</td>
              <td>${Number(c.clicks).toLocaleString('pt-BR')}</td>
              <td>${c.ctr}%</td>
              <td>R$ ${c.spend}</td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    `;
    } else if (type === 'creatives') {
        const creatives = data.creatives as Array<Record<string, unknown>> || [];
        tableHtml = `
      <table>
        <thead>
          <tr>
            <th>Criativo</th>
            <th>Tipo</th>
            <th>CTR</th>
            <th>CPC</th>
            <th>Score</th>
          </tr>
        </thead>
        <tbody>
          ${creatives.map(c => `
            <tr>
              <td>${c.name}</td>
              <td>${c.type}</td>
              <td>${c.ctr}%</td>
              <td>R$ ${c.cpc}</td>
              <td>${c.score}%</td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    `;
    } else if (type === 'audits') {
        const audits = data.audits as Array<Record<string, unknown>> || [];
        tableHtml = `
      <table>
        <thead>
          <tr>
            <th>Criativo</th>
            <th>Status</th>
            <th>Conformidade</th>
            <th>Performance</th>
          </tr>
        </thead>
        <tbody>
          ${audits.map(a => `
            <tr>
              <td>${a.creative_name}</td>
              <td><span class="status-${a.status}">${a.status}</span></td>
              <td>${a.compliance_score || 0}%</td>
              <td>${a.performance_score || 0}%</td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    `;
    }

    return `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${title} - ClickHero</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; background: #0d0d12; color: #e5e5e5; padding: 40px; }
    .container { max-width: 1200px; margin: 0 auto; }
    .header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 40px; padding-bottom: 20px; border-bottom: 1px solid #2a2a35; }
    .logo { font-size: 24px; font-weight: bold; color: #ff6b35; }
    .report-info { text-align: right; color: #8a8a9a; font-size: 14px; }
    h1 { font-size: 28px; margin-bottom: 8px; }
    .summary { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 16px; margin-bottom: 40px; }
    .metric { background: #1a1a24; padding: 20px; border-radius: 12px; }
    .metric-value { font-size: 28px; font-weight: bold; color: #ff6b35; }
    .metric-label { font-size: 13px; color: #8a8a9a; margin-top: 4px; }
    table { width: 100%; border-collapse: collapse; background: #1a1a24; border-radius: 12px; overflow: hidden; }
    th, td { padding: 14px 16px; text-align: left; border-bottom: 1px solid #2a2a35; }
    th { background: #22222e; font-weight: 600; font-size: 13px; text-transform: uppercase; color: #8a8a9a; }
    td { font-size: 14px; }
    tr:last-child td { border-bottom: none; }
    .status-active, .status-approved { color: #22c55e; }
    .status-paused, .status-rejected { color: #ef4444; }
    .status-review { color: #eab308; }
    .footer { margin-top: 40px; padding-top: 20px; border-top: 1px solid #2a2a35; text-align: center; color: #8a8a9a; font-size: 12px; }
    @media print {
      body { background: white; color: #1a1a24; padding: 20px; }
      .metric, table { background: #f5f5f5; }
      th { background: #e5e5e5; }
      .logo { color: #ff6b35; }
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <div>
        <div class="logo">⚡ ClickHero</div>
        <h1>${title}</h1>
      </div>
      <div class="report-info">
        <div>${data.company_name}</div>
        <div>${data.date_from} até ${data.date_to}</div>
      </div>
    </div>

    <div class="summary">
      ${Object.entries(summary).map(([key, value]) => `
        <div class="metric">
          <div class="metric-value">${typeof value === 'number' ? value.toLocaleString('pt-BR') : value}</div>
          <div class="metric-label">${formatMetricLabel(key)}</div>
        </div>
      `).join('')}
    </div>

    ${tableHtml}

    <div class="footer">
      Relatório gerado em ${new Date().toLocaleString('pt-BR')} • ClickHero Ads Analyzer
    </div>
  </div>
</body>
</html>`;
}

function formatMetricLabel(key: string): string {
    const labels: Record<string, string> = {
        total_campaigns: 'Total de Campanhas',
        active_campaigns: 'Campanhas Ativas',
        total_impressions: 'Impressões',
        total_clicks: 'Cliques',
        total_spend: 'Gasto Total',
        total_conversions: 'Conversões',
        avg_ctr: 'CTR Médio',
        avg_cpc: 'CPC Médio',
        total_creatives: 'Total de Criativos',
        avg_performance: 'Score Médio',
        total_audits: 'Total de Auditorias',
        approved: 'Aprovadas',
        rejected: 'Rejeitadas',
        review: 'Em Revisão',
        avg_compliance: 'Conformidade Média',
    };
    return labels[key] || key;
}

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface AuditResult {
    brand_violations: Array<{
        keyword_id: string;
        text: string;
        match_type: string;
        issue: string;
        severity: 'high' | 'medium';
    }>;
    geo_violations: Array<{
        city: string;
        region: string;
        clicks: number;
        cost: number;
        issue: string;
        severity: 'high' | 'medium';
    }>;
    brand_health_score: number;
}

Deno.serve(async (req) => {
    // Handle CORS preflight requests
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const { company_id } = await req.json();

        if (!company_id) throw new Error('Company ID is required');

        // Extract and verify Auth Token manually (since verify_jwt will be false)
        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            return new Response(JSON.stringify({ error: 'Missing Authorization header' }), {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 401,
            });
        }

        const token = authHeader.replace('Bearer ', '');
        const { data: { user }, error: authError } = await supabase.auth.getUser(token);

        if (authError || !user) {
            return new Response(JSON.stringify({ error: 'Invalid Token', details: authError }), {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 401,
            });
        }

        // 1. Fetch Configuration (Mocked for now, normally from policies)
        const BRAND_TERMS = ['clickhero', 'click hero'];
        const ALLOWED_CITIES = ['São Paulo', 'Curitiba', 'Rio de Janeiro', 'Belo Horizonte'];
        const GEO_CLICK_THRESHOLD = 5; // Stricter for demo

        // 2. Audit Keywords (Brand Protection)
        const { data: keywords, error: kwError } = await supabase
            .from('google_keywords')
            .select('id, text, match_type, status')
            .eq('status', 'ENABLED');

        if (kwError) throw kwError;

        const brandViolations: AuditResult['brand_violations'] = [];

        for (const kw of (keywords || [])) {
            const lowerText = kw.text.toLowerCase();
            const containsBrand = BRAND_TERMS.some(term => lowerText.includes(term));

            if (containsBrand) {
                // Rule: Brand terms must not be BROAD match without explicit control
                // In this simplified audit, BROAD on brand is a violation
                if (kw.match_type === 'BROAD') {
                    brandViolations.push({
                        keyword_id: kw.id,
                        text: kw.text,
                        match_type: kw.match_type,
                        issue: 'Termo de marca em correspondência ampla (Risco de Canibalização)',
                        severity: 'high'
                    });
                }
            }
        }

        // 3. Audit Geo Performance
        const { data: geoStats, error: geoError } = await supabase
            .from('google_geo_performance')
            .select('*');

        if (geoError) throw geoError;

        const geoViolations: AuditResult['geo_violations'] = [];

        for (const stat of (geoStats || [])) {
            // Check if city is allowed
            // Note: city_name might be null for generic regions
            // Logic: If city is NOT in allowed list AND clicks > threshold = Violation
            if (stat.city_name && !ALLOWED_CITIES.includes(stat.city_name)) {
                if (stat.clicks > GEO_CLICK_THRESHOLD) {
                    geoViolations.push({
                        city: stat.city_name,
                        region: stat.region_name,
                        clicks: stat.clicks,
                        cost: stat.cost_micros / 1000000,
                        issue: `Free BID: Veiculação fora da praça permitida (> ${GEO_CLICK_THRESHOLD} cliques)`,
                        severity: 'high'
                    });
                }
            }
        }

        // 4. Calculate Score
        let score = 100;
        score -= (brandViolations.length * 15);
        score -= (geoViolations.length * 10);
        score = Math.max(0, score); // Min 0

        const result: AuditResult = {
            brand_violations: brandViolations,
            geo_violations: geoViolations,
            brand_health_score: score
        };

        return new Response(JSON.stringify(result), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 200,
        });

    } catch (error) {
        return new Response(JSON.stringify({ error: String(error) }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 500,
        });
    }
});

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const META_API_VERSION = "v24.0";
const META_API_BASE = `https://graph.facebook.com/${META_API_VERSION}`;

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface AdActionRequest {
    creative_id: string; // Internal ID
    action: 'pause' | 'activate' | 'preview';
}

serve(async (req) => {
    // Handle CORS
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        // Get auth header
        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        // Verify user
        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        // Get user's company
        const { data: userData, error: userError } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (userError || !userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const body = await req.json() as AdActionRequest;
        const { creative_id, action } = body;

        if (!creative_id || !action) {
            throw new Error('Missing creative_id or action');
        }

        // Get ad and integration via campaign
        const { data: creative, error: creativeError } = await supabase
            .from('creatives')
            .select(`
                *, 
                campaigns (
                    integrations (
                        id, access_token, status
                    )
                )
            `)
            .eq('id', creative_id)
            .eq('company_id', userData.company_id)
            .single();

        if (creativeError || !creative) {
            throw new Error('Creative (Ad) not found');
        }

        const integration = creative.campaigns?.integrations;
        if (!integration || integration.status !== 'active') {
            throw new Error('No active integration found');
        }

        const accessToken = integration.access_token;
        const externalAdId = creative.external_id;

        if (!externalAdId) {
            throw new Error('Ad external ID not found');
        }

        let metaUrl = '';
        let metaMethod = 'POST';
        let metaBody: any = { access_token: accessToken };
        let dbUpdates: any = { updated_at: new Date().toISOString() };
        let syncType = `ad_${action}`;
        let responsePayload: any = {};

        switch (action) {
            case 'pause':
            case 'activate':
                metaUrl = `${META_API_BASE}/${externalAdId}`;
                metaBody.status = action === 'activate' ? 'ACTIVE' : 'PAUSED';
                dbUpdates.status = action === 'activate' ? 'active' : 'paused';
                break;

            case 'preview':
                // For preview we use GET and return the iframe
                metaUrl = `${META_API_BASE}/${externalAdId}/previews?ad_format=DESKTOP_FEED_STANDARD&access_token=${accessToken}`;
                metaMethod = 'GET';
                metaBody = null; // GET requests don't have body
                dbUpdates = null; // No DB update for preview
                syncType = 'ad_preview';
                break;

            default:
                throw new Error('Invalid action');
        }

        console.log(`Executing ${action} on ${externalAdId} via ${metaUrl}`);

        const fetchOptions: any = {
            method: metaMethod,
            headers: { 'Content-Type': 'application/json' }
        };

        if (metaBody) {
            fetchOptions.body = JSON.stringify(metaBody);
        }

        const metaResponse = await fetch(metaUrl, fetchOptions);

        if (!metaResponse.ok) {
            const errorData = await metaResponse.json();
            console.error('Meta API error:', errorData);
            throw new Error(`Failed to ${action} ad: ${errorData.error?.message || 'Unknown error'}`);
        }

        const responseData = await metaResponse.json();

        if (action === 'preview') {
            responsePayload.preview_content = responseData.data?.[0]?.body; // Meta returns HTML in body field of data list
        }

        // Update local database
        if (dbUpdates) {
            const { error: updateError } = await supabase
                .from('creatives')
                .update(dbUpdates)
                .eq('id', creative_id);

            if (updateError) {
                console.error('Database update error:', updateError);
            }
        }

        // Log the action (except preview to avoid spam)
        if (action !== 'preview') {
            await supabase.from('sync_history').insert({
                company_id: userData.company_id,
                integration_id: integration.id,
                sync_type: syncType,
                status: 'completed',
                records_synced: 1,
                details: {
                    creative_id,
                    external_id: externalAdId,
                    action,
                    meta_response: responseData
                },
            });
        }

        return new Response(
            JSON.stringify({
                success: true,
                creative_id,
                action,
                updates: dbUpdates,
                ...responsePayload
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('Ad action error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const META_API_VERSION = "v24.0";
const META_API_BASE = `https://graph.facebook.com/${META_API_VERSION}`;

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface AdSetActionRequest {
    adset_id: string;
    action: 'pause' | 'activate' | 'update_budget';
    payload?: {
        daily_budget?: number; // em centavos
        lifetime_budget?: number; // em centavos
    };
}

serve(async (req) => {
    // Handle CORS
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        // Get auth header
        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        // Verify user
        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        // Get user's company
        const { data: userData, error: userError } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (userError || !userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const body = await req.json() as AdSetActionRequest;
        const { adset_id, action, payload } = body;

        if (!adset_id || !action) {
            throw new Error('Missing adset_id or action');
        }

        // Get adset and integration via campaign
        const { data: adSet, error: adSetError } = await supabase
            .from('ad_sets')
            .select(`
                *, 
                campaigns (
                    integrations (
                        id, access_token, status
                    )
                )
            `)
            .eq('id', adset_id)
            .eq('company_id', userData.company_id)
            .single();

        if (adSetError || !adSet) {
            throw new Error('Ad Set not found');
        }

        const integration = adSet.campaigns?.integrations;
        if (!integration || integration.status !== 'active') {
            throw new Error('No active integration found');
        }

        const accessToken = integration.access_token;
        const externalAdSetId = adSet.external_id;

        if (!externalAdSetId) {
            throw new Error('Ad Set external ID not found');
        }

        let metaUrl = `${META_API_BASE}/${externalAdSetId}`;
        let metaBody: any = { access_token: accessToken };
        let dbUpdates: any = { updated_at: new Date().toISOString() };
        let syncType = `adset_${action}`;

        switch (action) {
            case 'pause':
            case 'activate':
                metaBody.status = action === 'activate' ? 'ACTIVE' : 'PAUSED';
                dbUpdates.status = action === 'activate' ? 'active' : 'paused';
                break;

            case 'update_budget':
                if (payload?.daily_budget) {
                    metaBody.daily_budget = payload.daily_budget;
                    dbUpdates.daily_budget = payload.daily_budget / 100;
                }
                if (payload?.lifetime_budget) {
                    metaBody.lifetime_budget = payload.lifetime_budget;
                    dbUpdates.lifetime_budget = payload.lifetime_budget / 100;
                }
                if (!payload?.daily_budget && !payload?.lifetime_budget) {
                    throw new Error('Missing budget value in payload');
                }
                break;

            default:
                throw new Error('Invalid action');
        }

        console.log(`Executing ${action} on ${externalAdSetId} via ${metaUrl}`);

        const metaResponse = await fetch(metaUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(metaBody),
        });

        if (!metaResponse.ok) {
            const errorData = await metaResponse.json();
            console.error('Meta API error:', errorData);
            throw new Error(`Failed to ${action} ad set: ${errorData.error?.message || 'Unknown error'}`);
        }

        const responseData = await metaResponse.json();

        // Update local database
        const { error: updateError } = await supabase
            .from('ad_sets')
            .update(dbUpdates)
            .eq('id', adset_id);

        if (updateError) {
            console.error('Database update error:', updateError);
        }

        // Log the action
        await supabase.from('sync_history').insert({
            company_id: userData.company_id,
            integration_id: integration.id,
            sync_type: syncType,
            status: 'completed',
            records_synced: 1,
            details: {
                adset_id,
                external_id: externalAdSetId,
                action,
                meta_response: responseData,
                db_updates: dbUpdates
            },
        });

        return new Response(
            JSON.stringify({
                success: true,
                adset_id,
                action,
                updates: dbUpdates,
                meta_response: responseData
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('Ad Set action error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const META_API_VERSION = "v24.0";
const META_API_BASE = `https://graph.facebook.com/${META_API_VERSION}`;

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface CampaignActionRequest {
    campaign_id: string;
    action: 'pause' | 'activate' | 'duplicate' | 'update_budget' | 'rename';
    payload?: {
        daily_budget?: number; // em centavos
        lifetime_budget?: number; // em centavos
        name?: string;
    };
}

serve(async (req) => {
    // Handle CORS
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        // Get auth header
        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        // Verify user
        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        // Get user's company
        const { data: userData, error: userError } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (userError || !userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const body = await req.json() as CampaignActionRequest;
        const { campaign_id, action, payload } = body;

        if (!campaign_id || !action) {
            throw new Error('Missing campaign_id or action');
        }

        // Get campaign and integration
        const { data: campaign, error: campaignError } = await supabase
            .from('campaigns')
            .select('*, integrations(*)')
            .eq('id', campaign_id)
            .eq('company_id', userData.company_id)
            .single();

        if (campaignError || !campaign) {
            throw new Error('Campaign not found');
        }

        const integration = campaign.integrations;
        if (!integration || integration.status !== 'active') {
            throw new Error('No active integration found');
        }

        const accessToken = integration.access_token;
        const externalCampaignId = campaign.external_id;

        if (!externalCampaignId) {
            throw new Error('Campaign external ID not found');
        }

        let metaUrl = '';
        let metaMethod = 'POST';
        let metaBody: any = { access_token: accessToken };
        let dbUpdates: any = { updated_at: new Date().toISOString() };
        let syncType = `campaign_${action}`;
        let details: any = {};

        switch (action) {
            case 'pause':
            case 'activate':
                metaUrl = `${META_API_BASE}/${externalCampaignId}`;
                metaBody.status = action === 'activate' ? 'ACTIVE' : 'PAUSED';
                dbUpdates.status = action === 'activate' ? 'active' : 'paused';
                break;

            case 'update_budget':
                metaUrl = `${META_API_BASE}/${externalCampaignId}`;
                if (payload?.daily_budget) {
                    metaBody.daily_budget = payload.daily_budget; // Meta expects cents as string/number
                    dbUpdates.daily_budget = payload.daily_budget / 100;
                }
                if (payload?.lifetime_budget) {
                    metaBody.lifetime_budget = payload.lifetime_budget;
                    dbUpdates.lifetime_budget = payload.lifetime_budget / 100;
                }
                if (!payload?.daily_budget && !payload?.lifetime_budget) {
                    throw new Error('Missing budget value in payload');
                }
                details.new_budget = payload.daily_budget || payload.lifetime_budget;
                break;

            case 'rename':
                metaUrl = `${META_API_BASE}/${externalCampaignId}`;
                if (!payload?.name) throw new Error('Missing name in payload');
                metaBody.name = payload.name;
                dbUpdates.name = payload.name;
                details.new_name = payload.name;
                break;

            case 'duplicate':
                metaUrl = `${META_API_BASE}/${externalCampaignId}/copies`;
                metaBody.status_option = 'PAUSED'; // Default to paused copy
                // Handle different rename strategies if needed
                if (payload?.name) {
                    // Note: Rename options format might differ, standard copy usually appends 'Copy'
                    // For simplicity we let Meta handle naming or update it after
                    // According to docs: rename_options parameter
                }
                // Duplicate doesn't update the original campaign in DB
                dbUpdates = null;
                syncType = 'campaign_duplicated';
                break;

            default:
                throw new Error('Invalid action');
        }

        console.log(`Executing ${action} on ${externalCampaignId} via ${metaUrl}`);

        const metaResponse = await fetch(metaUrl, {
            method: metaMethod,
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(metaBody),
        });

        if (!metaResponse.ok) {
            const errorData = await metaResponse.json();
            console.error('Meta API error:', errorData);
            throw new Error(`Failed to ${action} campaign: ${errorData.error?.message || 'Unknown error'}`);
        }

        const responseData = await metaResponse.json();

        // If duplicate, receive new ID
        if (action === 'duplicate' && responseData.id) {
            // In a real scenario, we should fetch the new campaign info and insert into DB
            // For now, next sync cycle will pick it up, or we can trigger sync-meta-data
            details.new_campaign_id = responseData.id;
        }

        // Update local database if applicable
        if (dbUpdates) {
            const { error: updateError } = await supabase
                .from('campaigns')
                .update(dbUpdates)
                .eq('id', campaign_id);

            if (updateError) {
                console.error('Database update error:', updateError);
                // Don't throw - Meta update succeeded
            }
        }

        // Log the action
        await supabase.from('sync_history').insert({
            company_id: userData.company_id,
            integration_id: integration.id,
            sync_type: syncType,
            status: 'completed',
            records_synced: 1,
            details: {
                campaign_id,
                external_id: externalCampaignId,
                action,
                meta_response: responseData,
                ...details
            },
        });

        return new Response(
            JSON.stringify({
                success: true,
                campaign_id,
                action,
                updates: dbUpdates,
                meta_response: responseData
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('Campaign action error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});
